   270→          }
   271→          pythonToUse = standalonePython
   272→        } else {
   273→          pythonToUse = this.pythonPath!
   274→        }
   275→      }
   276→
   277→      onProgress?.('Creating virtual environment...', 40)
   278→      const venvPython = getVenvPython()
   279→
   280→      if (!fs.existsSync(venvPython)) {
   281→        await execAsync(`"${pythonToUse}" -m venv "${xttsVenvDir}"`, { timeout: 120000 })
   282→      }
   283→
   284→      if (!fs.existsSync(venvPython)) {
   285→        return { success: false, error: 'Failed to create virtual environment' }
   286→      }
   287→
