import React, { createContext, useEffect, useState, useMemo, useCallback } from 'react'
import type { VoiceContextValue } from './types.js'
import { useTTSHandlers } from './ttsHandlers.js'
import { useSTTHandlers } from './sttHandlers.js'

export const VoiceContext = createContext<VoiceContextValue | null>(null)

export function VoiceProvider({ children }: { children: React.ReactNode }): React.ReactElement {
  const [settingsLoaded, setSettingsLoaded] = useState(false)

  // Initialize TTS handlers
  const tts = useTTSHandlers({ settingsLoaded })

  // Create save function for STT handlers
  const saveVoiceSetting = useCallback(async (key: string, value: boolean | number | string) => {
    if (!settingsLoaded || !window.electronAPI) return
    const settings = await window.electronAPI?.getSettings()
    await window.electronAPI?.saveSettings({ ...settings, [key]: value })
  }, [settingsLoaded])

  // Initialize STT handlers
  const stt = useSTTHandlers({ saveVoiceSetting })

  // Load settings on mount
  useEffect(() => {
    if (!window.electronAPI) {
      setSettingsLoaded(true)
      return
    }
    window.electronAPI?.getSettings().then((settings) => {
      if (settings.voiceOutputEnabled !== undefined) tts.setVoiceOutputEnabledState(settings.voiceOutputEnabled)
      if (settings.voiceSilenceThreshold !== undefined) stt.setSilenceThresholdState(settings.voiceSilenceThreshold)
      if (settings.voiceVolume !== undefined) tts.setVolumeState(settings.voiceVolume)
      if (settings.voiceSpeed !== undefined) {
        tts.setSpeedState(settings.voiceSpeed)
        window.electronAPI?.voiceApplySettings?.({ ttsSpeed: settings.voiceSpeed })
      }
      if (settings.voiceSkipOnNew !== undefined) tts.setSkipOnNewState(settings.voiceSkipOnNew)
      setSettingsLoaded(true)
    }).catch(() => setSettingsLoaded(true))

    // Load global voice settings for project override feature
    window.electronAPI?.voiceGetSettings?.()?.then((voiceSettings) => {
      if (voiceSettings) {
        tts.refs.globalVoiceRef.current = {
          voice: voiceSettings.ttsVoice || '',
          engine: voiceSettings.ttsEngine || 'piper'
        }
      }
    })?.catch(e => console.error('Failed to load global voice settings:', e))
  }, [])

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      // Cancel any running processQueue
      tts.refs.processingGenerationRef.current++
      // Unblock any hung audio promise
      if (tts.refs.audioResolveRef.current) {
        tts.refs.audioResolveRef.current()
        tts.refs.audioResolveRef.current = null
      }
      // Clean up audio element and blob URL
      if (tts.refs.audioRef.current) {
        tts.refs.audioRef.current.pause()
        tts.refs.audioRef.current = null
      }
      if (tts.refs.audioUrlRef.current) {
        URL.revokeObjectURL(tts.refs.audioUrlRef.current)
        tts.refs.audioUrlRef.current = null
      }
      if (stt.refs.silenceTimerRef.current) {
        clearTimeout(stt.refs.silenceTimerRef.current)
      }
      if (stt.refs.whisperRef.current) {
        stt.refs.whisperRef.current.destroy()
        stt.refs.whisperRef.current = null
      }
    }
  }, [])

  const value = useMemo((): VoiceContextValue => ({
    // Voice Output
    voiceOutputEnabled: tts.voiceOutputEnabled,
    setVoiceOutputEnabled: tts.setVoiceOutputEnabled,
    speakText: tts.speakText,
    stopSpeaking: tts.stopSpeaking,
    isSpeaking: tts.isSpeaking,
    volume: tts.volume,
    setVolume: tts.setVolume,
    speed: tts.speed,
    setSpeed: tts.setSpeed,
    skipOnNew: tts.skipOnNew,
    setSkipOnNew: tts.setSkipOnNew,
    setProjectVoice: tts.setProjectVoice,
    // Voice Input
    isRecording: stt.isRecording,
    isModelLoading: stt.isModelLoading,
    isModelLoaded: stt.isModelLoaded,
    modelLoadProgress: stt.modelLoadProgress,
    modelLoadStatus: stt.modelLoadStatus,
    currentTranscription: stt.currentTranscription,
    whisperModel: stt.whisperModel,
    setWhisperModel: stt.setWhisperModel,
    audioLevel: stt.audioLevel,
    silenceThreshold: stt.silenceThreshold,
    setSilenceThreshold: stt.setSilenceThreshold,
    startRecording: stt.startRecording,
    stopRecording: stt.stopRecording
  }), [
    tts.voiceOutputEnabled,
    tts.setVoiceOutputEnabled,
    tts.speakText,
    tts.stopSpeaking,
    tts.isSpeaking,
    tts.volume,
    tts.setVolume,
    tts.speed,
    tts.setSpeed,
    tts.skipOnNew,
    tts.setSkipOnNew,
    tts.setProjectVoice,
    stt.isRecording,
    stt.isModelLoading,
    stt.isModelLoaded,
    stt.modelLoadProgress,
    stt.modelLoadStatus,
    stt.currentTranscription,
    stt.whisperModel,
    stt.setWhisperModel,
    stt.audioLevel,
    stt.silenceThreshold,
    stt.setSilenceThreshold,
    stt.startRecording,
    stt.stopRecording
  ])

  return (
    <VoiceContext.Provider value={value}>
      {children}
    </VoiceContext.Provider>
  )
}

import { useCallback, useRef, useState } from 'react'
import type { WhisperModelSize, WhisperInstance, WhisperTranscriberConfig, STTRefs } from './types.js'
import { WHISPER_MODEL_URLS, WHISPER_MODEL_SIZES } from './constants.js'

// Dynamic import for whisper-web-transcriber - only loaded when voice input is actually used
// This saves ~4.5MB bundle size when voice features are disabled
let WhisperTranscriberClass: (new (config: WhisperTranscriberConfig) => WhisperInstance) | null = null

async function loadWhisperTranscriber(): Promise<new (config: WhisperTranscriberConfig) => WhisperInstance> {
  if (!WhisperTranscriberClass) {
    const module = await import('whisper-web-transcriber')
    WhisperTranscriberClass = module.WhisperTranscriber as new (config: WhisperTranscriberConfig) => WhisperInstance
  }
  return WhisperTranscriberClass
}

export interface UseSTTHandlersOptions {
  saveVoiceSetting: (key: string, value: boolean | number | string) => void
}

export interface UseSTTHandlersResult {
  // State
  isRecording: boolean
  isModelLoading: boolean
  isModelLoaded: boolean
  modelLoadProgress: number
  modelLoadStatus: string
  currentTranscription: string
  whisperModel: WhisperModelSize
  audioLevel: number
  silenceThreshold: number

  // Actions
  setWhisperModel: (model: WhisperModelSize) => void
  setSilenceThreshold: (threshold: number) => void
  startRecording: (onTranscription: (text: string) => void) => Promise<void>
  stopRecording: () => void

  // Refs for cleanup
  refs: STTRefs

  // State setters for settings loading
  setWhisperModelState: (model: WhisperModelSize) => void
  setSilenceThresholdState: (threshold: number) => void
}

export function useSTTHandlers({ saveVoiceSetting }: UseSTTHandlersOptions): UseSTTHandlersResult {
  // Voice Input (STT) state
  const [isRecording, setIsRecording] = useState(false)
  const [isModelLoading, setIsModelLoading] = useState(false)
  const [isModelLoaded, setIsModelLoaded] = useState(false)
  const [modelLoadProgress, setModelLoadProgress] = useState(0)
  const [modelLoadStatus, setModelLoadStatus] = useState('')
  const [whisperModel, setWhisperModelState] = useState<WhisperModelSize>('base.en')
  const [currentTranscription, setCurrentTranscription] = useState('')
  const [audioLevel, setAudioLevel] = useState(0)
  const [silenceThreshold, setSilenceThresholdState] = useState(5)

  // Refs
  const whisperRef = useRef<WhisperInstance | null>(null)
  const onTranscriptionRef = useRef<((text: string) => void) | null>(null)
  const finalTranscriptionRef = useRef<string>('')
  const silenceTimerRef = useRef<NodeJS.Timeout | null>(null)
  const isRecordingRef = useRef(false)

  // Audio monitoring refs
  const audioContextRef = useRef<AudioContext | null>(null)
  const analyserRef = useRef<AnalyserNode | null>(null)
  const audioStreamRef = useRef<MediaStream | null>(null)
  const levelIntervalRef = useRef<number | null>(null)
  const silenceStartRef = useRef<number | null>(null)
  const silenceThresholdRef = useRef(silenceThreshold)
  const speechDetectedRef = useRef(false) // true if audio went above threshold since last chunk
  const processingUtteranceRef = useRef(false) // guard against re-entry during stop/submit/restart

  const refs: STTRefs = {
    whisperRef,
    onTranscriptionRef,
    finalTranscriptionRef,
    silenceTimerRef,
    isRecordingRef
  }

  // Start audio level monitoring
  const startAudioMonitoring = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true })
      audioStreamRef.current = stream
      const audioCtx = new AudioContext()
      audioContextRef.current = audioCtx
      const source = audioCtx.createMediaStreamSource(stream)
      const analyser = audioCtx.createAnalyser()
      analyser.fftSize = 256
      analyser.smoothingTimeConstant = 0.3
      source.connect(analyser)
      analyserRef.current = analyser

      const dataArray = new Uint8Array(analyser.frequencyBinCount)
      levelIntervalRef.current = window.setInterval(() => {
        if (!analyserRef.current || !isRecordingRef.current) return
        analyserRef.current.getByteFrequencyData(dataArray)
        const avg = dataArray.reduce((sum, v) => sum + v, 0) / dataArray.length
        const level = Math.round((avg / 255) * 100)
        setAudioLevel(level)

        const threshold = silenceThresholdRef.current
        if (level < threshold) {
          // Audio is below threshold (silence)
          if (!silenceStartRef.current) {
            silenceStartRef.current = Date.now()
          } else if (!processingUtteranceRef.current) {
            const silenceDuration = Date.now() - silenceStartRef.current
            // After 2s of silence with speech detected: submit transcription,
            // then stop/restart Whisper to clear the audio buffer
            if (silenceDuration > 2000 && speechDetectedRef.current &&
                finalTranscriptionRef.current.trim() &&
                isRecordingRef.current && whisperRef.current) {
              processingUtteranceRef.current = true

              const callback = onTranscriptionRef.current
              const textToSend = finalTranscriptionRef.current.trim()
              finalTranscriptionRef.current = ''
              setCurrentTranscription('')
              silenceStartRef.current = null
              speechDetectedRef.current = false

              if (callback && textToSend) {
                callback(textToSend)
              }

              // Stop and restart to clear Whisper's accumulated audio buffer
              whisperRef.current.stopRecording()
              if (isRecordingRef.current && whisperRef.current) {
                whisperRef.current.startRecording().catch((error) => {
                  console.error('Failed to restart recording after silence:', error)
                  setIsRecording(false)
                  isRecordingRef.current = false
                })
              }
              processingUtteranceRef.current = false
            }
          }
        } else {
          // Audio is above threshold (speaking)
          silenceStartRef.current = null
          speechDetectedRef.current = true
        }
      }, 100)
    } catch (error) {
      console.error('Failed to start audio monitoring:', error)
    }
  }, [])

  // Stop audio level monitoring
  const stopAudioMonitoring = useCallback(() => {
    if (levelIntervalRef.current !== null) {
      clearInterval(levelIntervalRef.current)
      levelIntervalRef.current = null
    }
    if (audioContextRef.current) {
      audioContextRef.current.close().catch(() => {})
      audioContextRef.current = null
    }
    if (audioStreamRef.current) {
      audioStreamRef.current.getTracks().forEach(t => t.stop())
      audioStreamRef.current = null
    }
    analyserRef.current = null
    silenceStartRef.current = null
    setAudioLevel(0)
  }, [])

  // Initialize Whisper transcriber - dynamically loads the module only when needed
  const initWhisper = useCallback(async () => {
    if (whisperRef.current || isModelLoading) return

    setIsModelLoading(true)
    setModelLoadStatus('Loading Whisper module...')

    try {
      const WhisperTranscriber = await loadWhisperTranscriber()

      setModelLoadStatus('Initializing...')

      const modelUrl = WHISPER_MODEL_URLS[whisperModel]
      const modelSizeMB = WHISPER_MODEL_SIZES[whisperModel]

      const transcriber = new WhisperTranscriber({
        modelUrl,
        modelSize: whisperModel,
        audioIntervalMs: 3000, // Feed audio to Whisper every 3s for near-realtime processing
        onTranscription: (text: string) => {
          // Library returns CUMULATIVE transcription of all audio since startRecording()
          // So we REPLACE (not append) the current transcription text
          const cleaned = text.trim()
            .replace(/\[BLANK_AUDIO\]/gi, '')
            .replace(/\[Silence\]/gi, '')
            .replace(/\(silence\)/gi, '')
            .replace(/\[Pause\]/gi, '')
            .replace(/\(Pause\)/gi, '')
            .replace(/\[inaudible\]/gi, '')
            .replace(/\[Music\]/gi, '')
            .replace(/\(Music\)/gi, '')
            .replace(/\[Applause\]/gi, '')
            .replace(/\[Laughter\]/gi, '')
            .replace(/\[.*?\]/g, '')
            .replace(/\(.*?\)/g, '')
            .replace(/♪.*?♪/g, '')
            .replace(/\*.*?\*/g, '')
            .replace(/^[\s.,!?]+$/, '')
            .replace(/^\.*$/, '')
            .trim()

          // Skip if empty or just short punctuation/artifacts
          // Also skip if no speech was detected (audio never exceeded threshold)
          if (cleaned && cleaned.length > 1 && !/^[.,!?\-]+$/.test(cleaned) && speechDetectedRef.current) {
            finalTranscriptionRef.current = cleaned
            setCurrentTranscription(cleaned)
          }
        },
        debug: true,
        onProgress: (progress: number) => {
          setModelLoadProgress(progress)
          setModelLoadStatus(`Downloading ${whisperModel} (${modelSizeMB}MB)... ${progress}%`)
        },
        onStatus: (status: string) => {
          setModelLoadStatus(status)
        }
      })

      // Override confirm() to auto-accept the model download prompt from helpers.js
      const originalConfirm = window.confirm
      window.confirm = () => true
      try {
        await transcriber.loadModel()
      } finally {
        window.confirm = originalConfirm
      }
      whisperRef.current = transcriber
      setIsModelLoaded(true)
      setModelLoadStatus('Model loaded')
    } catch (error: unknown) {
      console.error('Failed to initialize Whisper:', error)
      setModelLoadStatus(`Error: ${error instanceof Error ? error.message : String(error)}`)
    } finally {
      setIsModelLoading(false)
    }
  }, [whisperModel, isModelLoading])

  // Set Whisper model (saves to settings)
  const setWhisperModel = useCallback((model: WhisperModelSize) => {
    setWhisperModelState(model)
    if (whisperRef.current) {
      whisperRef.current.destroy()
      whisperRef.current = null
      setIsModelLoaded(false)
    }
    saveVoiceSetting('whisperModel', model)
  }, [saveVoiceSetting])

  // Set silence threshold (saves to settings)
  const setSilenceThreshold = useCallback((threshold: number) => {
    setSilenceThresholdState(threshold)
    silenceThresholdRef.current = threshold
    saveVoiceSetting('voiceSilenceThreshold', threshold)
  }, [saveVoiceSetting])

  // Start recording and transcribing
  const startRecording = useCallback(async (onTranscription: (text: string) => void) => {
    if (isRecording) return

    onTranscriptionRef.current = onTranscription
    finalTranscriptionRef.current = ''
    setCurrentTranscription('')
    silenceStartRef.current = null
    speechDetectedRef.current = false

    if (silenceTimerRef.current) {
      clearTimeout(silenceTimerRef.current)
      silenceTimerRef.current = null
    }

    if (!whisperRef.current) {
      await initWhisper()
    }

    if (!whisperRef.current) {
      console.error('Whisper not initialized')
      return
    }

    try {
      await whisperRef.current.startRecording()
      await startAudioMonitoring()
      setIsRecording(true)
      isRecordingRef.current = true
    } catch (error: unknown) {
      console.error('Failed to start recording:', error)
      const errorMessage = error instanceof Error ? error.message : ''
      const errorName = error instanceof Error ? error.name : ''
      if (errorMessage.includes('Permission denied') || errorName === 'NotAllowedError') {
        alert('Microphone access denied. Please allow microphone access in your browser/system settings.')
      }
    }
  }, [isRecording, initWhisper, startAudioMonitoring])

  // Stop recording
  const stopRecording = useCallback(() => {
    if (!isRecording || !whisperRef.current) return

    if (silenceTimerRef.current) {
      clearTimeout(silenceTimerRef.current)
      silenceTimerRef.current = null
    }

    whisperRef.current.stopRecording()
    stopAudioMonitoring()
    setIsRecording(false)
    isRecordingRef.current = false

    if (onTranscriptionRef.current && finalTranscriptionRef.current.trim()) {
      onTranscriptionRef.current(finalTranscriptionRef.current.trim())
    }

    onTranscriptionRef.current = null
    finalTranscriptionRef.current = ''
    setCurrentTranscription('')
  }, [isRecording, stopAudioMonitoring])

  return {
    isRecording,
    isModelLoading,
    isModelLoaded,
    modelLoadProgress,
    modelLoadStatus,
    currentTranscription,
    whisperModel,
    audioLevel,
    silenceThreshold,
    setWhisperModel,
    setSilenceThreshold,
    startRecording,
    stopRecording,
    refs,
    setWhisperModelState,
    setSilenceThresholdState
  }
}

import { useCallback, useMemo, useRef, useEffect, useState } from 'react'
import type { ProjectVoiceSettings, TTSRefs } from './types.js'

export interface UseTTSHandlersOptions {
  settingsLoaded: boolean
}

export interface UseTTSHandlersResult {
  // State
  voiceOutputEnabled: boolean
  isSpeaking: boolean
  volume: number
  speed: number
  skipOnNew: boolean

  // Setters
  setVoiceOutputEnabled: (enabled: boolean) => void
  setVolume: (volume: number) => void
  setSpeed: (speed: number) => void
  setSkipOnNew: (skip: boolean) => void
  setProjectVoice: (settings: ProjectVoiceSettings | null) => void

  // Actions
  speakText: (text: string) => void
  stopSpeaking: () => void

  // Refs for external use
  refs: TTSRefs

  // State setters for settings loading
  setVoiceOutputEnabledState: (enabled: boolean) => void
  setVolumeState: (volume: number) => void
  setSpeedState: (speed: number) => void
  setSkipOnNewState: (skip: boolean) => void
}

export function useTTSHandlers({ settingsLoaded }: UseTTSHandlersOptions): UseTTSHandlersResult {
  // Voice Output (TTS) state
  const [voiceOutputEnabled, setVoiceOutputEnabledState] = useState(false)
  const [isSpeaking, setIsSpeaking] = useState(false)
  const [volume, setVolumeState] = useState(1.0)
  const [speed, setSpeedState] = useState(1.0)
  const [skipOnNew, setSkipOnNewState] = useState(false)

  // Refs
  const audioRef = useRef<HTMLAudioElement | null>(null)
  const audioUrlRef = useRef<string | null>(null)
  const speakQueueRef = useRef<string[]>([])
  const isProcessingRef = useRef(false)
  const voiceOutputEnabledRef = useRef(voiceOutputEnabled)
  const skipOnNewRef = useRef(skipOnNew)
  const volumeRef = useRef(volume)
  const processingGenerationRef = useRef(0)
  const audioResolveRef = useRef<(() => void) | null>(null)
  const projectVoiceRef = useRef<ProjectVoiceSettings | null>(null)
  const globalVoiceRef = useRef<{ voice: string; engine: string } | null>(null)

  const refs: TTSRefs = {
    audioRef,
    audioUrlRef,
    speakQueueRef,
    isProcessingRef,
    voiceOutputEnabledRef,
    skipOnNewRef,
    volumeRef,
    processingGenerationRef,
    audioResolveRef,
    projectVoiceRef,
    globalVoiceRef
  }

  // Keep refs in sync to avoid stale closures
  useEffect(() => {
    voiceOutputEnabledRef.current = voiceOutputEnabled
  }, [voiceOutputEnabled])

  useEffect(() => {
    skipOnNewRef.current = skipOnNew
  }, [skipOnNew])

  useEffect(() => {
    volumeRef.current = volume
  }, [volume])

  // Save a single voice setting
  const saveVoiceSetting = useCallback(async (key: string, value: boolean | number) => {
    if (!settingsLoaded || !window.electronAPI) return
    const settings = await window.electronAPI?.getSettings()
    await window.electronAPI?.saveSettings({ ...settings, [key]: value })
  }, [settingsLoaded])

  // Debounced save for slider-based settings (volume, speed) to avoid excessive IPC calls
  const debouncedSaveRef = useRef<{ timer: NodeJS.Timeout | null; pending: Map<string, boolean | number> }>({
    timer: null,
    pending: new Map()
  })

  const debouncedSaveVoiceSetting = useMemo(() => {
    return (key: string, value: boolean | number) => {
      debouncedSaveRef.current.pending.set(key, value)
      if (debouncedSaveRef.current.timer) {
        clearTimeout(debouncedSaveRef.current.timer)
      }
      debouncedSaveRef.current.timer = setTimeout(() => {
        debouncedSaveRef.current.pending.forEach((val, k) => {
          saveVoiceSetting(k, val)
        })
        debouncedSaveRef.current.pending.clear()
        debouncedSaveRef.current.timer = null
      }, 500)
    }
  }, [saveVoiceSetting])

  // Wrapper for setVoiceOutputEnabled that saves setting
  const setVoiceOutputEnabled = useCallback((enabled: boolean) => {
    setVoiceOutputEnabledState(enabled)
    saveVoiceSetting('voiceOutputEnabled', enabled)
  }, [saveVoiceSetting])

  // Update volume on current audio
  const setVolume = useCallback((v: number) => {
    const clamped = Math.max(0, Math.min(1, v))
    setVolumeState(clamped)
    if (audioRef.current) {
      audioRef.current.volume = clamped
    }
    debouncedSaveVoiceSetting('voiceVolume', clamped)
  }, [debouncedSaveVoiceSetting])

  // Update speed and notify backend
  const setSpeed = useCallback((s: number) => {
    const clamped = Math.max(0.5, Math.min(2.0, s))
    setSpeedState(clamped)
    window.electronAPI?.voiceApplySettings?.({ ttsSpeed: clamped })
    debouncedSaveVoiceSetting('voiceSpeed', clamped)
  }, [debouncedSaveVoiceSetting])

  // Update skipOnNew and save
  const setSkipOnNew = useCallback((skip: boolean) => {
    setSkipOnNewState(skip)
    saveVoiceSetting('voiceSkipOnNew', skip)
  }, [saveVoiceSetting])

  // Set per-project voice override
  const setProjectVoice = useCallback((settings: ProjectVoiceSettings | null) => {
    projectVoiceRef.current = settings
    if (settings?.ttsVoice && settings?.ttsEngine) {
      window.electronAPI?.voiceApplySettings?.({
        ttsVoice: settings.ttsVoice,
        ttsEngine: settings.ttsEngine
      })
    } else if (globalVoiceRef.current) {
      window.electronAPI?.voiceApplySettings?.({
        ttsVoice: globalVoiceRef.current.voice,
        ttsEngine: globalVoiceRef.current.engine as 'piper' | 'xtts'
      })
    }
  }, [])

  // Process the speak queue
  const processQueue = useCallback(async () => {
    if (isProcessingRef.current || speakQueueRef.current.length === 0) return

    isProcessingRef.current = true
    setIsSpeaking(true)
    const myGeneration = processingGenerationRef.current

    while (speakQueueRef.current.length > 0) {
      if (processingGenerationRef.current !== myGeneration) {
        return
      }

      const text = speakQueueRef.current.shift()
      if (!text) continue

      try {
        if (!window.electronAPI?.voiceSpeak) {
          continue
        }
        const result = await window.electronAPI?.voiceSpeak?.(text)

        if (processingGenerationRef.current !== myGeneration) {
          return
        }

        if (result?.success && result.audioData) {
          const base64Audio = result.audioData
          await new Promise<void>((resolve) => {
            audioResolveRef.current = resolve

            const audioData = Uint8Array.from(atob(base64Audio), c => c.charCodeAt(0))
            const blob = new Blob([audioData], { type: 'audio/wav' })
            const url = URL.createObjectURL(blob)
            const audio = new Audio(url)
            audio.volume = volumeRef.current
            audioRef.current = audio
            audioUrlRef.current = url

            const cleanup = () => {
              URL.revokeObjectURL(url)
              if (audioRef.current === audio) {
                audioRef.current = null
              }
              if (audioUrlRef.current === url) {
                audioUrlRef.current = null
              }
              audioResolveRef.current = null
              resolve()
            }

            audio.onended = cleanup
            audio.onerror = (e) => {
              console.error('Audio playback error:', e)
              cleanup()
            }

            audio.play().catch(e => {
              console.error('Failed to play audio:', e)
              cleanup()
            })
          })
        } else if (result?.error) {
          console.error('TTS error:', result.error)
        }
      } catch (e) {
        console.error('TTS error:', e)
      }
    }

    if (processingGenerationRef.current === myGeneration) {
      isProcessingRef.current = false
      setIsSpeaking(false)
    }
  }, [])

  const speakText = useCallback((text: string) => {
    if (!voiceOutputEnabledRef.current) return

    const cleanText = text
      .replace(/\x1b\[[0-9;]*[a-zA-Z]/g, '')
      .replace(/[\r\n]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()

    console.log('[TTS Debug] speakText called:', {
      originalLength: text.length,
      cleanedLength: cleanText.length,
      original: text.substring(0, 100),
      cleaned: cleanText.substring(0, 100)
    })

    if (cleanText.length < 3) return

    if (skipOnNewRef.current) {
      speakQueueRef.current = []
      processingGenerationRef.current++
      if (audioResolveRef.current) {
        audioResolveRef.current()
        audioResolveRef.current = null
      }
      if (audioRef.current) {
        audioRef.current.pause()
        audioRef.current = null
      }
      isProcessingRef.current = false
    }

    speakQueueRef.current.push(cleanText)
    processQueue()
  }, [processQueue])

  const stopSpeaking = useCallback(() => {
    speakQueueRef.current = []
    processingGenerationRef.current++
    if (audioResolveRef.current) {
      audioResolveRef.current()
      audioResolveRef.current = null
    }
    if (audioRef.current) {
      audioRef.current.pause()
      audioRef.current = null
    }
    window.electronAPI?.voiceStopSpeaking?.()
    setIsSpeaking(false)
    isProcessingRef.current = false
  }, [])

  // Stop speaking when disabled
  useEffect(() => {
    if (!voiceOutputEnabled) {
      stopSpeaking()
    }
  }, [voiceOutputEnabled, stopSpeaking])

  return {
    voiceOutputEnabled,
    isSpeaking,
    volume,
    speed,
    skipOnNew,
    setVoiceOutputEnabled,
    setVolume,
    setSpeed,
    setSkipOnNew,
    setProjectVoice,
    speakText,
    stopSpeaking,
    refs,
    setVoiceOutputEnabledState,
    setVolumeState,
    setSpeedState,
    setSkipOnNewState
  }
}

import { app } from 'electron'
import * as fs from 'fs'
import * as path from 'path'
import { exec } from 'child_process'
import { promisify } from 'util'
import type { XTTSLanguage, XTTSVoice } from './xtts-paths.js'
import type { XTTSServer } from './xtts-server.js'

const execAsync = promisify(exec)

export interface SpeakOptions {
  temperature?: number
  speed?: number
  topK?: number
  topP?: number
  repetitionPenalty?: number
}

export interface SpeakResult {
  success: boolean
  audioData?: string
  error?: string
}

export interface ExtractClipResult {
  success: boolean
  outputPath?: string
  dataUrl?: string
  error?: string
}

export interface MediaDurationResult {
  success: boolean
  duration?: number
  error?: string
}

export async function synthesizeSpeech(
  server: XTTSServer,
  text: string,
  voice: XTTSVoice,
  language?: XTTSLanguage,
  options?: SpeakOptions
): Promise<SpeakResult> {
  try {
    const tempDir = app.getPath('temp')
    const outputPath = path.join(tempDir, `xtts_${Date.now()}.wav`)
    const lang = language || voice.language

    const result = await server.sendCommand({
      action: 'speak',
      text,
      reference_audio: voice.referencePath,
      language: lang,
      output_path: outputPath,
      temperature: options?.temperature ?? 0.65,
      speed: options?.speed ?? 1.0,
      top_k: options?.topK ?? 50,
      top_p: options?.topP ?? 0.85,
      repetition_penalty: options?.repetitionPenalty ?? 2.0
    }) as { success: boolean; error?: string }

    if (result.success && fs.existsSync(outputPath)) {
      const audioBuffer = fs.readFileSync(outputPath)
      const audioData = audioBuffer.toString('base64')
      fs.unlinkSync(outputPath)
      return { success: true, audioData }
    }

    return { success: false, error: result.error || 'TTS generation failed' }
  } catch (e) {
    const error = e instanceof Error ? e.message : String(e)
    return { success: false, error }
  }
}

export async function getMediaDuration(filePath: string): Promise<MediaDurationResult> {
  try {
    const { stdout } = await execAsync(
      `ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "${filePath}"`,
      { timeout: 30000 }
    )
    const duration = parseFloat(stdout.trim())
    if (isNaN(duration)) {
      return { success: false, error: 'Could not determine duration' }
    }
    return { success: true, duration }
  } catch (e) {
    const error = e instanceof Error ? e.message : String(e)
    if (error.includes('not found') || error.includes('ENOENT')) {
      return { success: false, error: 'ffmpeg not found. Please install ffmpeg to use this feature.' }
    }
    return { success: false, error }
  }
}

export async function extractAudioClip(
  inputPath: string,
  startTime: number,
  endTime: number,
  outputPath?: string
): Promise<ExtractClipResult> {
  try {
    const duration = endTime - startTime
    if (duration <= 0) {
      return { success: false, error: 'End time must be greater than start time' }
    }
    if (duration < 3) {
      return { success: false, error: 'Clip must be at least 3 seconds long' }
    }
    if (duration > 30) {
      return { success: false, error: 'Clip should be 30 seconds or less for best results' }
    }

    const outPath = outputPath || path.join(app.getPath('temp'), `xtts_clip_${Date.now()}.wav`)

    await execAsync(
      `ffmpeg -y -ss ${startTime} -t ${duration} -i "${inputPath}" -vn -acodec pcm_s16le -ar 22050 -ac 1 "${outPath}"`,
      { timeout: 60000 }
    )

    if (!fs.existsSync(outPath)) {
      return { success: false, error: 'Failed to extract audio' }
    }

    const audioData = fs.readFileSync(outPath)
    const dataUrl = `data:audio/wav;base64,${audioData.toString('base64')}`

    return { success: true, outputPath: outPath, dataUrl }
  } catch (e) {
    const error = e instanceof Error ? e.message : String(e)
    if (error.includes('not found') || error.includes('ENOENT')) {
      return { success: false, error: 'ffmpeg not found. Please install ffmpeg to use this feature.' }
    }
    return { success: false, error }
  }
}

export function getTempDir(): string {
  return app.getPath('temp')
}

