    54→    const pythonToUse = fs.existsSync(venvPython) ? venvPython : this.pythonPath
    55→
    56→    if (!pythonToUse) {
    57→      return false
    58→    }
    59→
    60→    this.ensureHelperScript()
    61→
    62→    return new Promise((resolve) => {
    63→      const proc = spawn(pythonToUse, [xttsScriptPath, 'server'])
    64→      this.serverProcess = proc
    65→      this.serverReady = false
    66→      this.responseBuffer = ''
    67→
    68→      proc.stdout.on('data', (data) => {
    69→        this.responseBuffer += data.toString()
    70→
    71→        const lines = this.responseBuffer.split('\n')
    72→        this.responseBuffer = lines.pop() || ''
    73→
    74→        for (const line of lines) {
    75→          if (!line.trim()) continue
    76→
    77→          try {
    78→            const response = JSON.parse(line)
    79→
    80→            if (response.status === 'ready') {
    81→              this.serverReady = true
    82→              resolve(true)
    83→              continue
    84→            }
    85→
    86→            const entry = this.pendingRequests.entries().next().value
    87→            if (entry) {
    88→              const [requestId, handlers] = entry
    89→              this.pendingRequests.delete(requestId)
    90→              handlers.resolve(response)
    91→            }
    92→          } catch (e) {
    93→            console.error('XTTS server parse error:', e, 'line:', line)
    94→          }
    95→        }
    96→      })
    97→
    98→      proc.stderr.on('data', (data) => {
    99→        console.log('XTTS server:', data.toString())
   100→      })
   101→
   102→      proc.on('close', (code) => {
   103→        this.serverProcess = null
   104→        this.serverReady = false
   105→
   106→        for (const [, handlers] of this.pendingRequests) {
   107→          handlers.reject(new Error(`Server exited with code ${code}`))
   108→        }
   109→        this.pendingRequests.clear()
   110→
   111→        if (!this.serverReady) {
   112→          resolve(false)
   113→        }
   114→      })
   115→
   116→      proc.on('error', () => {
   117→        this.serverProcess = null
   118→        this.serverReady = false
   119→        resolve(false)
   120→      })
   121→
   122→      setTimeout(() => {
   123→        if (!this.serverReady) {
   124→          console.error('XTTS server startup timeout')
   125→          this.stop()
   126→          resolve(false)
   127→        }
   128→      }, 120000)
   129→    })
   130→  }
   131→
   132→  stop(): void {
   133→    if (this.serverProcess) {
   134→      try {
   135→        this.serverProcess.stdin?.write(JSON.stringify({ action: 'quit' }) + '\n')
   136→      } catch {
   137→        // Ignore write errors
   138→      }
   139→
   140→      setTimeout(() => {
   141→        if (this.serverProcess) {
   142→          this.serverProcess.kill()
   143→          this.serverProcess = null
   144→        }
   145→      }, 1000)
   146→    }
   147→    this.serverReady = false
   148→  }
   149→
   150→  async sendCommand(command: object): Promise<unknown> {
   151→    if (!this.serverProcess || !this.serverReady) {
   152→      const started = await this.start()
   153→      if (!started) {
   154→        throw new Error('Failed to start XTTS server')
   155→      }
   156→    }
   157→
   158→    return new Promise((resolve, reject) => {
   159→      const requestId = `${Date.now()}-${Math.random()}`
   160→      this.pendingRequests.set(requestId, { resolve, reject })
   161→
   162→      try {
   163→        this.serverProcess!.stdin?.write(JSON.stringify(command) + '\n')
   164→      } catch (err) {
   165→        this.pendingRequests.delete(requestId)
   166→        reject(err)
   167→      }
   168→
   169→      setTimeout(() => {
   170→        if (this.pendingRequests.has(requestId)) {
   171→          this.pendingRequests.delete(requestId)
   172→          reject(new Error('Request timeout'))
   173→        }
   174→      }, 300000)
   175→    })
   176→  }
   177→
   178→  private ensureHelperScript(): void {
   179→    ensureDir(xttsDir)
   180→    fs.writeFileSync(xttsScriptPath, XTTS_HELPER_SCRIPT)
   181→    if (!isWindows) {
   182→      fs.chmodSync(xttsScriptPath, 0o755)
   183→    }
   184→  }
